import * as types from '../actions/actionTypes'
import _ from 'lodash'

import { all } from './all'
import { levels } from './levels'
import initialState from './initialState';

const createTable = (size) => {
    const foo = _.take(_.shuffle(all), size / 2)
    let bar = []
    let i = 0
    _.each(foo, (x) => {
        bar.push({key: x.key, ch: x.hiragana, id: i++})
        bar.push({key: x.key, ch: x.romanization, id: i++})
    })
    bar = _.shuffle(bar)
    if (size % 2) {
        bar = bar.slice(0, size/2).concat([{id: -1}]).concat(bar.slice(size/2))
    }
    return bar
}

const cardTableReducer = (state = initialState, action) => {
    switch (action.type) {
        case types.CREATE_TABLE:
            const l = levels[action.level]
            const width = l[0]
            const height = l[1]
            const list = createTable(width * height)
            let played = []
            if ((width * height) % 2) {
                played.push(-1)
            }
            const newState = Object.assign({}, state, {
                list,
                width,
                height,
                opened: [],
                played: played,
                level: action.level
            })
            return newState
        case types.OPEN_CARD:
            if (state.opened.indexOf(action.id) >= 0) {
                return Object.assign({}, state, {
                    opened: []
                })
            }
            
            if (state.opened.length > 1) {
                return Object.assign({}, state, {
                    opened: []
                })
            }
            return Object.assign({}, state, {
                opened: [ ...state.opened, action.id]
            })
        case types.CHECK_PAIR:
            const a = state.list.filter(x => { return x.id === state.opened[0] })[0]
            const b = state.list.filter(x => { return x.id === state.opened[1] })[0]
            if (a && b && a.key === b.key) {
                return Object.assign({}, state, {
                    opened: [],
                    played: [...state.played, a.id, b.id]
                })
            }
            return Object.assign({}, state, {
                opened: []
            })
        default:
            return state
    }
}

export default cardTableReducer


