import React from 'react'
import _ from 'lodash'

import { connect } from 'react-redux'

import Card from './Card'
import { checkOpened, createTable } from '../actions/cardTableActions';

class CardTable extends React.Component {
    componentDidUpdate() {
        if (this.props.opened.length === 2) {
            setTimeout(() => { this.props.checkPair() }, 500)
        }
        if (this.props.list.length === this.props.played.length) {
            if (this.props.level === 10) {
                this.props.newGame(10)
            } else {
                this.props.newGame(this.props.level + 1)
            }
        }
    }
    render() {
        return (
            <div className={`cardField x${this.props.width}`}>
                { this.props.list.map(x => <Card
                    key={x.id} ch={x.ch} id={x.id}
                    opened={this.props.opened.indexOf(x.id) >= 0}
                    played={this.props.played.indexOf(x.id) >= 0}/>)}
            </div>
        )
    }
} 

const mapProps = (state, ownProps) => {
    return {
        list: state.cardTable.list,
        width: state.cardTable.width,
        height: state.cardTable.height,
        opened: state.cardTable.opened,
        played: state.cardTable.played,
        matched: state.cardTable.matched,
        level: state.cardTable.level
    }
}
const mapActions = (dispatch) => {
    return {
        checkPair: () => {
            dispatch(checkOpened())
        },
        newGame: (width, height) => {
            dispatch(createTable(width, height))
        }
    }
}

export default connect(mapProps, mapActions)(CardTable)


