import React from 'react'
import { openCard } from '../actions/cardTableActions';

import { connect } from 'react-redux'

class Card extends React.Component {
    constructor(props) {
        super(props)
        this.clickHandler = this.clickHandler.bind(this)
    }

    clickHandler() {
        this.props.openCard(this.props.id)
    }

    render() {
        return (
            <div className={ this.props.opened ? 'card open' : 'card'}
            onClick={this.clickHandler}>
                { 
                    this.props.played || <div className="flipper">
                        <div className="back">
                        </div>
                        <div className="front">
                            <p>{this.props.ch}</p>
                        </div>
                    </div>
                }
            </div>
        )
    }
}

const mapProps = (state, ownProps) => {
    return {
    }
}

const mapActions = (dispatch) => {
    return {
        openCard: (id) => {
            dispatch(openCard(id))
        }
    }
}

export default connect(mapProps, mapActions)(Card)


