import * as types from './actionTypes'

export const createTable = (level) => {
    return {
        type: types.CREATE_TABLE,
        level
    }
}

export const openCard = (id) => {
    return {
        type: types.OPEN_CARD,
        id
    }
}

export const checkOpened = () => {
    return {
        type: types.CHECK_PAIR
    }
}


